// ══════════════════════════════════════════════════════════════════════════════
// ══  API PÚBLICA: AlbaCuentos
// ══  Funciones que consume cefe-lactancia.html
// ══════════════════════════════════════════════════════════════════════════════

var AlbaCuentos = (function() {

  // Días de vida del bebé (lee desde D global si está disponible)
  function getDias() {
    if (typeof ageD === 'function') return ageD();
    return 0;
  }

  // Nombre del bebé
  function getNombre() {
    if (typeof D !== 'undefined' && D.bebe) return D.bebe.apodo || D.bebe.nombre || 'Cefe';
    return 'Cefe';
  }

  // Nombre de la familia (padres)
  function getFamilia() {
    var familia = { bebe: getNombre(), padre: 'Manu', madre: 'Sari' };
    if (typeof D !== 'undefined' && D.padres) {
      D.padres.forEach(function(p) {
        if (!p) return;
        var nombre = (p.nombre || '') + (p.apellido ? ' ' + p.apellido : '');
        if (p.rol === 'padre') familia.padre = nombre.trim() || 'Manu';
        if (p.rol === 'madre') familia.madre = nombre.trim() || 'Sari';
      });
    }
    return familia;
  }

  // ── Cuentos disponibles y bloqueados según edad ────────────────────────────

  function getCuentosPorGrupo() {
    var dias = getDias();
    var grupos = {
      cuna:      { label: 'Cuna', desc: 'Nanas y rimas', emoji: '\uD83C\uDF19', minDias: 0 },
      cortos:    { label: 'Cuentos cortos', desc: 'Primeras historias', emoji: '\uD83D\uDCDA', minDias: 90 },
      fabulas:   { label: 'F\u00e1bulas', desc: 'Esopo y La Fontaine', emoji: '\uD83E\uDD8A', minDias: 1095 },
      parabolas: { label: 'Par\u00e1bolas', desc: 'Sabidur\u00eda antigua', emoji: '\uD83C\uDF1F', minDias: 1460 },
      mitologia: { label: 'Mitolog\u00eda', desc: 'Dioses y h\u00e9roes', emoji: '\uD83C\uDFDB\uFE0F', minDias: 1825 },
      latinoamerica: { label: 'Am\u00e9rica Latina', desc: 'Leyendas de nuestra tierra', emoji: '\uD83C\uDF0E', minDias: 365 },
      clasicos:  { label: 'Cl\u00e1sicos', desc: 'Los grandes cuentos', emoji: '\uD83C\uDFF0', minDias: 365 },
      aventura:  { label: 'Aventura', desc: 'Historias largas', emoji: '\u2694\uFE0F', minDias: 1095 },
      mayores:   { label: 'Para m\u00e1s grandes', desc: 'Mitos y leyendas', emoji: '\uD83C\uDF0D', minDias: 2190 },
    };

    var resultado = {};
    Object.keys(grupos).forEach(function(gid) {
      var g = grupos[gid];
      resultado[gid] = {
        label: g.label,
        desc: g.desc,
        emoji: g.emoji,
        minDias: g.minDias,
        disponible: dias >= g.minDias,
        diasRestantes: Math.max(0, g.minDias - dias),
        cuentos: ALBA_CUENTOS.filter(function(c) { return c.grupo === gid; })
      };
    });
    return resultado;
  }

  function getCuentoById(id) {
    return ALBA_CUENTOS.find(function(c) { return c.id === id; }) || null;
  }

  // ── Personalización de texto ────────────────────────────────────────────────

  function personalizarTexto(texto, nombreProtagonista) {
    var familia = getFamilia();
    var bebe = getNombre();
    // Reemplazar placeholders
    texto = texto.replace(/\{BEBE\}/g, bebe);
    texto = texto.replace(/\{PADRE\}/g, familia.padre);
    texto = texto.replace(/\{MADRE\}/g, familia.madre);
    // Si se especificó personalizar el protagonista
    if (nombreProtagonista) {
      texto = texto.replace(/\{PROTAGONISTA\}/g, nombreProtagonista);
    }
    return texto;
  }

  // Reemplazar nombre del protagonista en el texto del cuento
  function reemplazarProtagonista(cuento, version, nuevoNombre) {
    var texto = version === 'corto' ? cuento.corto : cuento.largo;
    if (!cuento.protagonista || !nuevoNombre) return texto;
    // Reemplaza la primera mención del protagonista (case-insensitive, solo en el texto)
    var regex = new RegExp(cuento.protagonista, 'gi');
    return texto.replace(regex, nuevoNombre);
  }

  // ── Generador de cuentos procedural (Nivel 1, sin IA) ─────────────────────

  function elegirAlAzar(arr, semilla) {
    // Si hay semilla, usar para reproducibilidad (mismo cuento para mismo día)
    var idx;
    if (semilla !== undefined) {
      idx = semilla % arr.length;
    } else {
      idx = Math.floor(Math.random() * arr.length);
    }
    return arr[idx];
  }

  function generarCuento(opciones) {
    // opciones: { protagonistaId, escenarioId, desafioId, aliadoId, objetoId, resolucionId }
    // Si no se especifica, elegir al azar
    opciones = opciones || {};
    var nombre = getNombre();
    var familia = getFamilia();

    var prot  = opciones.protagonistaId
      ? ALBA_PLANTILLAS.protagonistas.find(function(x){return x.id===opciones.protagonistaId;}) || ALBA_PLANTILLAS.protagonistas[0]
      : elegirAlAzar(ALBA_PLANTILLAS.protagonistas);

    var escen = opciones.escenarioId
      ? ALBA_PLANTILLAS.escenarios.find(function(x){return x.id===opciones.escenarioId;}) || elegirAlAzar(ALBA_PLANTILLAS.escenarios)
      : elegirAlAzar(ALBA_PLANTILLAS.escenarios);

    var desaf = opciones.desafioId
      ? ALBA_PLANTILLAS.desafios.find(function(x){return x.id===opciones.desafioId;}) || elegirAlAzar(ALBA_PLANTILLAS.desafios)
      : elegirAlAzar(ALBA_PLANTILLAS.desafios);

    var alia  = opciones.aliadoId
      ? ALBA_PLANTILLAS.aliados.find(function(x){return x.id===opciones.aliadoId;}) || elegirAlAzar(ALBA_PLANTILLAS.aliados)
      : elegirAlAzar(ALBA_PLANTILLAS.aliados);

    var obj   = opciones.objetoId
      ? ALBA_PLANTILLAS.objetos.find(function(x){return x.id===opciones.objetoId;}) || elegirAlAzar(ALBA_PLANTILLAS.objetos)
      : elegirAlAzar(ALBA_PLANTILLAS.objetos);

    var resol = opciones.resolucionId
      ? ALBA_PLANTILLAS.resoluciones.find(function(x){return x.id===opciones.resolucionId;}) || elegirAlAzar(ALBA_PLANTILLAS.resoluciones)
      : elegirAlAzar(ALBA_PLANTILLAS.resoluciones);

    // Resolver texto del protagonista (reemplazar {BEBE} si corresponde)
    var protTxt = prot.txt.replace(/\{BEBE\}/g, nombre);

    // Construir el cuento
    var parrafos = [
      'Hab\u00eda una vez ' + protTxt + ' que viv\u00eda en ' + escen.txt + '.',

      'Un d\u00eda, ' + protTxt.split(' ')[0].toLowerCase() === 'un' || protTxt.split(' ')[0].toLowerCase() === 'una'
        ? protTxt
        : (nombre === protTxt ? nombre : 'nuestro protagonista') +
        ' descubri\u00f3 que ' + desaf.txt + '.',

      'No sab\u00eda qu\u00e9 hacer. Pero entonces apareci\u00f3 ' + alia.txt + ' con ' + obj.txt + '.',

      '\u00abEste objeto te ayudar\u00e1\u00bb, dijo con voz tranquila. \u00abPero el verdadero poder viene de adentro tuyo.\u00bb',

      'Y as\u00ed fue: ' + (nombre === protTxt ? nombre : 'el protagonista') + ' ' + resol.txt,

      'Y cuando volvi\u00f3 a casa esa noche, ' + familia.padre + ' y ' + familia.madre + ' lo esperaban con un abrazo. \u201cTe quer\u00e9mos much\u00edsimo\u201d, dijeron.',

      'Y todos durmieron felices.'
    ];

    return {
      titulo: 'El cuento de ' + nombre + ' en ' + escen.emoji + ' ' + escen.txt.split(' ')[3] || 'el mundo m\u00e1gico',
      texto: parrafos.join('\n\n'),
      variables: { prot: prot, escen: escen, desaf: desaf, alia: alia, obj: obj, resol: resol }
    };
  }

  // ── Recomendación Céfiro ────────────────────────────────────────────────────

  function getCuentoDelDia() {
    var dias = getDias();
    var hora = new Date().getHours();
    var disponibles = ALBA_CUENTOS.filter(function(c) { return c.edadMin <= dias; });
    if (disponibles.length === 0) return null;
    // Usar día del año como semilla para consistencia
    var hoy = new Date();
    var semilla = (hoy.getMonth() * 31 + hoy.getDate()) % disponibles.length;
    return disponibles[semilla];
  }

  function getMensajeCefiro() {
    var hora = new Date().getHours();
    var nombre = getNombre();
    var cuento = getCuentoDelDia();
    if (!cuento) return null;
    if (hora >= 20 || hora < 6) {
      return '\uD83C\uDF19 Buenas noches. \u00bfLe le\u00e9mos a ' + nombre + ' \u00ab' + cuento.titulo + '\u00bb?';
    }
    if (hora >= 14 && hora < 18) {
      return '\uD83D\uDCDA Hora del cuento. Hoy C\u00e9firo sugiere: \u00ab' + cuento.titulo + '\u00bb.';
    }
    return null;
  }

  // ── Dado mágico: genera una combinación aleatoria para el generador ─────────

  function tirarDado() {
    return {
      protagonistaId: elegirAlAzar(ALBA_PLANTILLAS.protagonistas).id,
      escenarioId:    elegirAlAzar(ALBA_PLANTILLAS.escenarios).id,
      desafioId:      elegirAlAzar(ALBA_PLANTILLAS.desafios).id,
      aliadoId:       elegirAlAzar(ALBA_PLANTILLAS.aliados).id,
      objetoId:       elegirAlAzar(ALBA_PLANTILLAS.objetos).id,
      resolucionId:   elegirAlAzar(ALBA_PLANTILLAS.resoluciones).id,
    };
  }

  // API pública
  return {
    getCuentosPorGrupo: getCuentosPorGrupo,
    getCuentoById: getCuentoById,
    personalizarTexto: personalizarTexto,
    reemplazarProtagonista: reemplazarProtagonista,
    getTexto: function(cuento, version, idioma) {
      // idioma: 'es' (default) | 'en'
      if (idioma === 'en') {
        return version === 'corto'
          ? (cuento.cortoEN || cuento.corto)
          : (cuento.largoEN || cuento.largo);
      }
      return version === 'corto' ? cuento.corto : cuento.largo;
    },
    generarCuento: generarCuento,
    getCuentoDelDia: getCuentoDelDia,
    getMensajeCefiro: getMensajeCefiro,
    tirarDado: tirarDado,
    totalCuentos: ALBA_CUENTOS.length,
  };

})();

// Confirmar carga
console.log('[Alba Cuentos] Cargado: ' + AlbaCuentos.totalCuentos + ' cuentos + generador procedural.');
